const getRows = (nodeName) => { try { return $node[nodeName].json.data || []; } catch(e) { return []; } };
const decisions = getRows('Export KB-05 Decisions');
const prompts = getRows('Export Active Prompts');
const tasks = getRows('Export Recent Tasks');

const backup = {
  version: 'v8.2',
  exported_at: new Date().toISOString(),
  decisions,
  prompts,
  tasks
};

return [{ json: { backup: JSON.stringify(backup, null, 2), filename: `coprem-backup-${new Date().toISOString().split('T')[0]}.json` } }];

